resources.preRequestScript:
const runId = Date.now().toString();
const start = new Date(Date.now() + 5 * 60 * 1000);
const end = new Date(start.getTime() + 60 * 60 * 1000);
insomnia.baseEnvironment.set('run_id', runId);
insomnia.baseEnvironment.set('start_at', start.toISOString());
insomnia.baseEnvironment.set('end_at', end.toISOString());

resources.afterResponseScript:
const body = insomnia.response.json();
insomnia.baseEnvironment.set('admin_token', body.access_token);
insomnia.test('administrator login returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('facility_id', body.id);
insomnia.test('facility creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('station_id', body.id);
insomnia.baseEnvironment.set('connector_id', body.connectors[0].id);
insomnia.test('station creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('driver_token', body.access_token);
insomnia.test('driver login returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('outsider_token', body.access_token);
insomnia.test('outsider login returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('vehicle_id', body.id);
insomnia.test('vehicle creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('reservation_id', body.reservation.id);
insomnia.test('reservation creation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));

const body = insomnia.response.json();
const started = new Date(body.started_at);
insomnia.baseEnvironment.set('session_id', body.id);
insomnia.baseEnvironment.set('recorded_1', new Date(started.getTime() + 1000).toISOString());
insomnia.baseEnvironment.set('recorded_2', new Date(started.getTime() + 2000).toISOString());
insomnia.baseEnvironment.set('recorded_3', new Date(started.getTime() + 3000).toISOString());
insomnia.baseEnvironment.set('recorded_4', new Date(started.getTime() + 4000).toISOString());
insomnia.baseEnvironment.set('before_start', new Date(started.getTime() - 1000).toISOString());
insomnia.baseEnvironment.set('outside_skew', new Date(Date.now() + 10 * 60 * 1000).toISOString());
insomnia.test('activation returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));
insomnia.test('session is ACTIVE', () => insomnia.expect(body.status).to.eql('ACTIVE'));

const body = insomnia.response.json();
insomnia.baseEnvironment.set('telemetry_id', body.id);
insomnia.test('first submission returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));
insomnia.test('canonical sample belongs to session', () => insomnia.expect(body.session_id).to.eql(insomnia.baseEnvironment.get('session_id')));
insomnia.test('platform timestamps are populated', () => { insomnia.expect(body.received_at).to.be.a('string'); insomnia.expect(body.created_at).to.be.a('string'); });

const body = insomnia.response.json();
insomnia.test('identical retry returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('retry returns canonical persisted ID', () => insomnia.expect(body.id).to.eql(insomnia.baseEnvironment.get('telemetry_id')));

const body = insomnia.response.json();
insomnia.test('conflicting retry returns 409', () => insomnia.expect(insomnia.response.code).to.eql(409));
insomnia.test('conflict has stable code', () => insomnia.expect(body.detail.code).to.eql('TELEMETRY_IDEMPOTENCY_CONFLICT'));

const body = insomnia.response.json();
insomnia.test('batch with new samples returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));
insomnia.test('duplicate key has one canonical entry', () => insomnia.expect(body).to.have.length(2));
insomnia.test('response preserves first key occurrence order', () => insomnia.expect(body.map(item => item.sample_id)).to.eql(['batch-a-' + insomnia.baseEnvironment.get('run_id'), 'batch-b-' + insomnia.baseEnvironment.get('run_id')]));

const body = insomnia.response.json();
insomnia.test('fully persisted identical batch returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('canonical retry entries are returned', () => insomnia.expect(body).to.have.length(2));

const body = insomnia.response.json();
insomnia.test('mixed batch returns 201', () => insomnia.expect(insomnia.response.code).to.eql(201));
insomnia.test('mixed batch returns both canonical entries', () => insomnia.expect(body).to.have.length(2));

const body = insomnia.response.json();
const ids = body.map(item => item.sample_id);
insomnia.test('telemetry list returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('list contains four persisted observations', () => insomnia.expect(body).to.have.length(4));
insomnia.test('failed batch persisted no partial sample', () => insomnia.expect(ids).to.not.include('must-rollback-' + insomnia.baseEnvironment.get('run_id')));
insomnia.test('list is ordered by recorded_at', () => insomnia.expect(body.map(item => item.recorded_at)).to.eql([...body.map(item => item.recorded_at)].sort()));

const body = insomnia.response.json();
insomnia.test('source filter returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('source filter only returns SIMULATOR', () => insomnia.expect(body.every(item => item.source === 'SIMULATOR')).to.eql(true));
insomnia.test('source filter returns expected observations', () => insomnia.expect(body).to.have.length(2));

const body = insomnia.response.json();
insomnia.test('telemetry retrieval returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('retrieval returns canonical sample', () => insomnia.expect(body.id).to.eql(insomnia.baseEnvironment.get('telemetry_id')));

const body = insomnia.response.json();
const completedRecorded = new Date(new Date(body.ended_at).getTime() - 1).toISOString();
insomnia.baseEnvironment.set('completed_recorded', completedRecorded);
insomnia.test('completion returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('session is COMPLETED', () => insomnia.expect(body.status).to.eql('COMPLETED'));

const document = insomnia.response.json();
const operations = [document.paths['/charging-sessions/{sessionId}/telemetry'].post, document.paths['/charging-sessions/{sessionId}/telemetry/batch'].post, document.paths['/charging-sessions/{sessionId}/telemetry'].get, document.paths['/telemetry/{telemetryId}'].get];
insomnia.test('OpenAPI returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('all telemetry operations declare Bearer security', () => insomnia.expect(operations.every(operation => JSON.stringify(operation.security) === JSON.stringify([{HTTPBearer: []}]))).to.eql(true));
insomnia.test('all telemetry operations document 401 and concealment 404', () => insomnia.expect(operations.every(operation => operation.responses['401'] && operation.responses['404'])).to.eql(true));
insomnia.test('ingestion operations document idempotent statuses', () => insomnia.expect(operations.slice(0, 2).every(operation => operation.responses['200'] && operation.responses['201'] && operation.responses['409'] && operation.responses['422'])).to.eql(true));

const body = insomnia.response.text();
const names = ['scep_telemetry_samples_received_total', 'scep_telemetry_samples_persisted_total', 'scep_telemetry_batch_ingestions_total', 'scep_telemetry_batch_failures_total', 'scep_telemetry_validation_failures_total', 'scep_telemetry_duplicate_submissions_total'];
insomnia.test('metrics returns 200', () => insomnia.expect(insomnia.response.code).to.eql(200));
insomnia.test('all SPEC-008 metrics are exposed', () => insomnia.expect(names.every(name => body.includes(name))).to.eql(true));
